import{_ as t,o,c as r,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"64. Fitness For Work","description":"","frontmatter":{"title":"64. Fitness For Work","eba":"Allied Health Professionals 2021-2026","topics":["ohs"]},"headers":[],"relativePath":"ebas/allied-health/leave/64-fitness-for-work.md","filePath":"ebas/allied-health/leave/64-fitness-for-work.md"}'),a={name:"ebas/allied-health/leave/64-fitness-for-work.md"};function i(s,e,l,p,h,c){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="_64-fitness-for-work" tabindex="-1">64. Fitness For Work <a class="header-anchor" href="#_64-fitness-for-work" aria-label="Permalink to &quot;64. Fitness For Work&quot;">​</a></h1><p><strong>64.1</strong> Fit for Work</p><p><strong>(a)</strong> The Employer is responsible for providing a workplace that is safe and without risk to health for Employees, so far as is reasonably practicable. This</p><p>responsibility includes compliance with Occupational Health and Safety legislation.</p><p><strong>(b)</strong> Each Employee is responsible for ensuring that they are fit to perform their duties without risk to the safety, health and well-being of themselves and others within the workplace, so far as is reasonably practicable. This responsibility includes compliance with lawful and reasonable measures put in place by the Employer related to Occupational Health and Safety requirements.</p><p><strong>64.2</strong> Addressing concerns about Fitness for Work</p><p><strong>(a)</strong> In the event an Employee’s manager forms a Reasonable Belief as defined at subclause 64.2(b) below that an Employee is unfit to perform their duties, the Employer will discuss their concerns with the Employee in a timely manner to promote physical, mental and emotional health so that Employees can safely undertake and sustain work.</p><p><strong>(b)</strong> In this clause 64 Reasonable Belief means a belief a reasonable person would hold based on sufficient evidence that supports a conclusion on the balance of probabilities. Nothing in this clause 64 permits an Employer to act contrary to the Health Records Act 2001 (Vic).</p><p><strong>(c)</strong> In this clause 64 Treating Medical Practitioner may, where relevant, include a psychologist.</p><p><strong>(d)</strong> The Employer will:</p><p><strong>(i)</strong> take all reasonable steps to give the Employee an opportunity to address any concerns which are the subject of the Reasonable Belief;</p><p><strong>(ii)</strong> inform the Employee of their right to have a representative, including a Union representative, at any time when meeting with the Employer to represent the Employee;</p><p><strong>(iii)</strong> genuinely consider the Employee’s response with a view to promoting physical, mental and emotional health so that Employees can safely undertake and sustain work; and</p><p><strong>(iv)</strong> take these responses into account in considering whether reasonable adjustments can be made in order that the Employee can safely undertake and sustain work.</p><p><strong>64.3</strong> Treating Medical Practitioner</p><p><strong>(a)</strong> Where, after discussion with the Employee, the Employer continues to have a Reasonable Belief that the Employee is unfit to perform the duties, the Employer may request that the Employee consent to the Employer obtaining a report from the Employee’s Treating Medical Practitioner through the Employee regarding the Employee’s fitness for work. Where the Employee consents, the Employee will advise the Employer of the Employee’s Treating Medical Practitioner, and the Employer will provide to the Employee, in writing, the concerns that form the basis of the Reasonable Belief and a copy of all correspondence the Employee can provide to their Employee’s Treating Medical Practitioner requesting a report to address the concerns.</p><p><strong>(b)</strong> The Employee will provide a copy of the relevant report to the Employer.</p><p><strong>(c)</strong> The Employer and Employee will meet to discuss the relevant report.</p><p><strong>(d)</strong> Where the Employee’s Treating Medical Practitioner indicates in the report that the Employee is fit for work this will be accepted by the Employer, except where the Employer continues to have a Reasonable Belief that the Employee is unfit for duty.</p><p><strong>64.4</strong> Independent Medical Examiner (IME)</p><p><strong>(a)</strong> Where:</p><p><strong>(i)</strong> the Employer continues to have a Reasonable Belief that the Employee is unfit for duty; or</p><p><strong>(ii)</strong> Employee does not consent to or provide a report from their Treating Medical Practitioner; the Employer may require the Employee to attend an IME who is not employed by the Employer.</p><p><strong>(b)</strong> Before the Employee attends an IME the Employer will provide the Employee with the name of the proposed IME.</p><p><strong>(c)</strong> If the Employee has concerns regarding the impartiality of the proposed IME notified in subclause 64.4(b), within three (3) business days or reasonable longer period to allow the Employee to consult with their Treating Medical Practitioner, the Employee will:</p><p><strong>(i)</strong> provide reasoning for their concerns, and</p><p><strong>(ii)</strong> may provide up to three (3) alternative IMEs for consideration by the Employer.</p><p><strong>(d)</strong> The Employer must:</p><p><strong>(i)</strong> consider the information provided by the Employee;</p><p><strong>(ii)</strong> not unreasonably refuse to agree to send the Employee to one of the alternative IMEs proposed by the Employee in lieu of the IME proposed by the Employer;</p><p><strong>(iii)</strong> notify the Employee of the practitioner the Employer has decided will undertake the IME; and</p><p><strong>(iv)</strong> include the reasons for their decision.</p><p><strong>(e)</strong> The Employee may:</p><p><strong>(i)</strong> supplement the material to be provided to the IME; and/or</p><p><strong>(ii)</strong> request to meet with the Employer to consult about the material the Employer proposes to provide the IME. The Employee&#39;s representative may attend the meeting and represent the Employee.</p><p><strong>64.5</strong> Where the Employee attends a medical practitioner under either subclause 64.3 or 64.4 above, the Employer will:</p><p><strong>(a)</strong> provide to the Employee a copy of any correspondence (including any supporting material) proposed to be provided to the medical practitioner and any resulting report;</p><p><strong>(b)</strong> pay for the cost of the appointment and report;</p><p><strong>(c)</strong> provide the Employee with a copy of any medical report it receives on the Employee’s capacity or fitness for work;</p><p><strong>(d)</strong> provide the Employee with paid leave to attend the medical practitioner without deduction from paid leave accruals or entitlements; and</p><p><strong>(e)</strong> reimburse the Employee for any other reasonable costs incurred by the Employee in attending the medical practitioner, including the travel allowance in <a href="/eba/ebas/allied-health/allowances/41-travelling-allowance.html">clause 41</a> (Travelling Allowance).</p><p><strong>64.6</strong> Nothing in this clause 64 prevents an Employer from taking any reasonable step to ensure a safe work environment in accordance with applicable legislation and this Agreement.</p><p><strong>64.7</strong> The Employer will respect an Employee’s privacy and ensure that any personal information provided by the Employee or a medical practitioner under this clause 64 is kept confidential.</p><p><strong>64.8</strong> The Employer must only seek information regarding the Employee’s capacity to work related to the concerns at subclause 64.2(a), including from any medical practitioner an Employee attends under subclause 64.3 or 64.4, and will not request confidential medical information under subclause 64.2, 64.3 and 64.4.</p><p><strong>64.9</strong> This clause 64. does not apply to an injury that is the subject of an active WorkCover claim. Matters regarding an Employee&#39;s Fitness for Work regarding an injury that is the subject of a WorkCover claim shall be managed in accordance with the WIRC Act including the Employer&#39;s obligation to provide a safe work environment.</p><p>Plain language terms: fit for duty, medical assessment.</p>',46)])])}const y=t(a,[["render",i]]);export{m as __pageData,y as default};
